SELECT AVG(version_count) AS average_versions_per_symbol
FROM (
    SELECT symbol_id, COUNT(version_id) AS version_count
    FROM symbol_versions
    GROUP BY symbol_id
) AS version_counts;

SELECT action, COUNT(*) AS action_count
FROM symbol_audit_trail
GROUP BY action;

SELECT COUNT(*) 
FROM symbol_relationships 
WHERE created_by = 1;

SELECT symbol_id, MAX(updated_date) AS latest_update
FROM symbol_versions
GROUP BY symbol_id;

SELECT COUNT(version_id) AS total_versions
FROM symbol_versions
WHERE symbol_id = 1;
